-- ============================================================
-- ตัวอย่าง queries ที่น่าสนใจสำหรับ Text-to-SQL
-- ============================================================
/*
Q: "รายได้รวมของแต่ละ client ที่จ่ายแล้ว"
SELECT c.name, SUM(i.total_cents) / 100.0 AS total_paid
FROM invoices i JOIN clients c ON i.client_id = c.id
WHERE i.status = 'paid'
GROUP BY c.name ORDER BY total_paid DESC;

Q: "user ที่ log เวลา billable มากที่สุดในเดือนที่ผ่านมา"
SELECT u.name, SUM(te.duration_seconds) / 3600.0 AS billable_hours
FROM time_entries te JOIN users u ON te.user_id = u.id
WHERE te.billable = TRUE AND te.started_at >= NOW() - INTERVAL '30 days'
GROUP BY u.name ORDER BY billable_hours DESC;

Q: "invoice ที่เลย due date แต่ยังไม่จ่าย"
SELECT invoice_number, due_date, total_cents / 100.0 AS total_usd,
       NOW()::date - due_date AS days_overdue
FROM invoices
WHERE status = 'sent' AND due_date < NOW()::date
ORDER BY days_overdue DESC;

Q: "project ที่มี budget เป็น hours แต่ยังไม่รู้ว่าใช้ไปเท่าไหร่"
SELECT p.name, p.budget_hours,
       COALESCE(SUM(te.duration_seconds) / 3600, 0) AS hours_used,
       p.budget_hours - COALESCE(SUM(te.duration_seconds) / 3600, 0) AS hours_remaining
FROM projects p
LEFT JOIN time_entries te ON p.id = te.project_id
WHERE p.budget_type = 'hours'
GROUP BY p.id, p.name, p.budget_hours;
*/
